  1	import * as React from 'react';
  2	import {
  3	  DiskMetadata,
  4	  DiskStates,
  5	  LocalVolumeDiscoveryResultKind,
  6	} from '@odf/core/types';
  7	import {
  8	  createLocalVolumeDiscovery,
  9	  updateLocalVolumeDiscovery,
 10	} from '@odf/core/utils';
 11	import {
 12	  getLabel,
 13	  getName,
 14	  getNamespace,
 15	  LocalVolumeDiscoveryResult,
 16	  SubscriptionKind,
 17	  SubscriptionModel,
 18	  useCustomTranslation,
 19	  useDeepCompareMemoize,
 20	} from '@odf/shared';
 21	import {
 22	  getNodeRoles,
 23	  humanizeBinaryBytes,
 24	  referenceForModel,
 25	} from '@odf/shared/utils';
 26	import {
 27	  ListPageBody,
 28	  ListPageFilter,
 29	  ListPageHeader,
 30	  NodeKind,
 31	  RowFilter,
 32	  RowProps,
 33	  TableColumn,
 34	  TableData,
 35	  useActiveColumns,
 36	  useK8sWatchResource,
 37	  useListPageFilter,
 38	  VirtualizedTable,
 39	} from '@openshift-console/dynamic-plugin-sdk';
 40	import cx from 'classnames';
 41	import * as _ from 'lodash-es';
 42	import { TFunction } from 'react-i18next';
 43	import { Button, EmptyState, EmptyStateVariant } from '@patternfly/react-core';
 44	import { sortable, wrappable } from '@patternfly/react-table';
 45	
 46	export const tableColumnInfo = [
 47	  { classNames: '', id: 'name' },
 48	  { classNames: '', id: 'state' },
 49	  { classNames: cx('pf-m-hidden', 'pf-m-visible-on-xl'), id: 'type' },
 50	  { classNames: cx('pf-m-hidden', 'pf-m-visible-on-2xl'), id: 'model' },
 51	  { classNames: cx('pf-m-hidden', 'pf-m-visible-on-2xl'), id: 'capacity' },
 52	  { classNames: cx('pf-m-hidden', 'pf-m-visible-on-2xl'), id: 'filesystem' },
 53	];
 54	
 55	const diskHeader = (t: TFunction): TableColumn<DiskMetadata>[] => [
 56	  {
 57	    title: t('Name'),
 58	    sort: 'path',
 59	    transforms: [sortable],
 60	    props: { className: tableColumnInfo[0].classNames },
 61	    id: tableColumnInfo[0].id,
 62	  },
 63	  {
 64	    title: t('Disk State'),
 65	    sort: 'status.state',
 66	    transforms: [sortable, wrappable],
 67	    props: { className: tableColumnInfo[1].classNames },
 68	    id: tableColumnInfo[1].id,
 69	  },
 70	  {
 71	    title: t('Type'),
 72	    sort: 'type',
 73	    transforms: [sortable, wrappable],
 74	    props: { className: tableColumnInfo[2].classNames },
 75	    id: tableColumnInfo[2].id,
 76	  },
 77	  {
 78	    title: t('Model'),
 79	    sort: 'model',
 80	    transforms: [sortable, wrappable],
 81	    props: { className: tableColumnInfo[3].classNames },
 82	    id: tableColumnInfo[3].id,
 83	  },
 84	  {
 85	    title: t('Capacity'),
 86	    sort: 'size',
 87	    transforms: [sortable, wrappable],
 88	    props: { className: tableColumnInfo[4].classNames },
 89	    id: tableColumnInfo[4].id,
 90	  },
 91	  {
 92	    title: t('Filesystem'),
 93	    sort: 'fstype',
 94	    transforms: [sortable, wrappable],
 95	    props: { className: tableColumnInfo[5].classNames },
 96	    id: tableColumnInfo[5].id,
 97	  },
 98	];
 99	
100	const DiskRow: React.FC<RowProps<DiskMetadata>> = ({
101	  obj,
102	  activeColumnIDs,
103	}) => (
104	  <>
105	    <TableData {...tableColumnInfo[0]} activeColumnIDs={activeColumnIDs}>
106	      {obj.path}
107	    </TableData>
108	    <TableData {...tableColumnInfo[1]} activeColumnIDs={activeColumnIDs}>
109	      {obj.status.state}
110	    </TableData>
111	    <TableData {...tableColumnInfo[2]} activeColumnIDs={activeColumnIDs}>
112	      {obj.type || '-'}
113	    </TableData>
114	    <TableData {...tableColumnInfo[3]} activeColumnIDs={activeColumnIDs}>
115	      {obj.model || '-'}
116	    </TableData>
117	    <TableData {...tableColumnInfo[4]} activeColumnIDs={activeColumnIDs}>
118	      {humanizeBinaryBytes(obj.size).string || '-'}
119	    </TableData>
120	    <TableData {...tableColumnInfo[5]} activeColumnIDs={activeColumnIDs}>
121	      {obj.fstype || '-'}
122	    </TableData>
123	  </>
124	);
125	
126	type DiskListProps = {
127	  data: DiskMetadata[];
128	  unfilteredData: DiskMetadata[];
129	  loadError: any;
130	  loaded: boolean;
131	  rowData: any;
132	  EmptyMsg: any;
133	};
134	const DisksList: React.FC<DiskListProps> = (props) => {
135	  const { t } = useCustomTranslation();
136	  const [columns] = useActiveColumns({
137	    columns: diskHeader(t),
138	    showNamespaceOverride: false,
139	    columnManagementID: null,
140	  });
141	  return (
142	    <VirtualizedTable
143	      {...props}
144	      aria-label={t('Disks List')}
145	      columns={columns}
146	      Row={DiskRow}
147	    />
148	  );
149	};
150	
151	export const NodesDisksListPage: React.FC<{ obj: NodeKind }> = ({ obj }) => {
152	  const { t } = useCustomTranslation();
153	
154	  const [lvdRequestError, setError] = React.useState('');
155	  const [lvdRequestInProgress, setProgress] = React.useState(false);
156	  const [subscription, subscriptionLoaded, subscriptionLoadError] =
157	    useK8sWatchResource<SubscriptionKind[]>({
158	      kind: referenceForModel(SubscriptionModel),
159	      fieldSelector: 'metadata.name=local-storage-operator',
160	      isList: true,
161	    });
162	
163	  const operatorNs = getNamespace(subscription?.[0]);
164	  const csvName = subscription?.[0]?.status?.installedCSV;
165	  const nodeName = getName(obj);
166	  const nodeRole = getNodeRoles(obj);
167	
168	  const [lvdResults, loaded, loadError] = useK8sWatchResource<
169	    LocalVolumeDiscoveryResultKind[]
170	  >({
171	    groupVersionKind: {
172	      group: LocalVolumeDiscoveryResult.apiGroup,
173	      version: LocalVolumeDiscoveryResult.apiVersion,
174	      kind: LocalVolumeDiscoveryResult.kind,
175	    },
176	    namespace: operatorNs,
177	    isList: true,
178	    optional: true,
179	  });
180	
181	  // Adding name property to fix issues with list page filter
182	  const unmemoizedDiskData =
183	    loaded && !loadError
184	      ? lvdResults
185	          ?.filter((result) => result.spec.nodeName === nodeName)
186	          ?.flatMap((disk) => disk?.status?.discoveredDevices)
187	          .map((disk) => ({
188	            ...disk,
189	            metadata: { name: disk.path }, // Adding name property for filtering
190	          }))
191	      : [];
192	  const diskData = useDeepCompareMemoize(unmemoizedDiskData, true);
193	
194	  const makeLocalVolumeDiscoverRequest = React.useCallback(
195	    async (ns: string) => {
196	      const nodeNameByHostnameLabel = getLabel(obj, 'kubernetes.io/hostname');
197	      setProgress(true);
198	      try {
199	        await updateLocalVolumeDiscovery(
200	          [nodeNameByHostnameLabel],
201	          ns,
202	          setError
203	        );
204	        setProgress(false);
205	      } catch (error) {
206	        if (error?.response?.status === 404) {
207	          try {
208	            await createLocalVolumeDiscovery(
209	              [nodeNameByHostnameLabel],
210	              ns,
211	              setError
212	            );
213	          } catch (createError) {
214	            setError(createError.message);
215	          }
216	        } else {
217	          setError(error.message);
218	        }
219	        setProgress(false);
220	      }
221	    },
222	    // eslint-disable-next-line react-hooks/exhaustive-deps
223	    [JSON.stringify(obj)]
224	  );
225	
226	  const EmptyMsg = React.useCallback(
227	    () => (
228	      <EmptyState variant={EmptyStateVariant.lg}>
229	        <p>{t('Disks Not Found')}</p>
230	        {csvName &&
231	          operatorNs &&
232	          !nodeRole.includes('control-plane') &&
233	          _.isEmpty(diskData) && (
234	            <Button
235	              isDisabled={lvdRequestInProgress}
236	              isLoading={lvdRequestInProgress}
237	              className="pf-v6-u-mt-0"
238	              onClick={() => makeLocalVolumeDiscoverRequest(operatorNs)}
239	              variant="primary"
240	            >
241	              {t('Discover Disks')}
242	            </Button>
243	          )}
244	      </EmptyState>
245	    ),
246	    [
247	      csvName,
248	      diskData,
249	      lvdRequestInProgress,
250	      makeLocalVolumeDiscoverRequest,
251	      nodeRole,
252	      operatorNs,
253	      t,
254	    ]
255	  );
256	
257	  const diskFilters: RowFilter<DiskMetadata>[] = [
258	    {
259	      type: 'disk-state',
260	      filterGroupName: t('Disk State'),
261	      reducer: (disk) => disk?.status?.state,
262	      items: [
263	        { id: DiskStates.Available, title: t('Available') },
264	        { id: DiskStates.NotAvailable, title: t('NotAvailable') },
265	        { id: DiskStates.Unknown, title: t('Unknown') },
266	      ],
267	      filter: (states, disk) => {
268	        if (!states || !states.selected || _.isEmpty(states.selected)) {
269	          return true;
270	        }
271	        const diskState = disk?.status.state;
272	        return (
273	          states.selected.includes(diskState) ||
274	          !_.includes(states.all, diskState)
275	        );
276	      },
277	    },
278	  ];
279	  const [data, filteredData, onFilterChange] = useListPageFilter(
280	    diskData,
281	    diskFilters
282	  );
283	  return (
284	    <>
285	      <ListPageHeader title={t('Disks')} />
286	      <ListPageBody>
287	        <ListPageFilter
288	          data={data}
289	          loaded={loaded}
290	          onFilterChange={onFilterChange}
291	          rowFilters={diskFilters}
292	          hideColumnManagement={true}
293	        />
294	        <DisksList
295	          data={filteredData}
296	          unfilteredData={data}
297	          loadError={lvdRequestError || subscriptionLoadError}
298	          loaded={subscriptionLoaded && loaded}
299	          EmptyMsg={EmptyMsg}
300	          rowData={{
301	            nodeName,
302	            operatorNs,
303	            csvName,
304	            lvdRequestInProgress,
305	          }}
306	        />
307	      </ListPageBody>
308	    </>
309	  );
310	};
311	
312	export default NodesDisksListPage;

